import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        int[] inDeg = new int[n];

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long c = edge[2];
            if (online[u] && online[v]) {
                adj.get(u).add(new int[]{v, (int) c});
                inDeg[v]++;
            }
        }

        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < n; i++) {
            if (online[i] && inDeg[i] == 0) {
                queue.add(i);
            }
        }

        List<Integer> topologicalOrder = new ArrayList<>();
        while (!queue.isEmpty()) {
            int u = queue.poll();
            topologicalOrder.add(u);
            for (int[] entry : adj.get(u)) {
                int v = entry[0];
                inDeg[v]--;
                if (inDeg[v] == 0) {
                    queue.add(v);
                }
            }
        }

        long[] max_m = new long[n];
        long[] min_sum = new long[n];
        Arrays.fill(max_m, Long.MIN_VALUE);
        max_m[0] = Long.MAX_VALUE;
        Arrays.fill(min_sum, Long.MAX_VALUE);
        min_sum[0] = 0;

        for (int u : topologicalOrder) {
            if (max_m[u] == Long.MIN_VALUE) continue;
            for (int[] entry : adj.get(u)) {
                int v = entry[0];
                long c = entry[1];
                long new_m = Math.min(max_m[u], c);
                long new_sum = min_sum[u] + c;
                if (new_sum <= k) {
                    if (new_m > max_m[v]) {
                        max_m[v] = new_m;
                        min_sum[v] = new_sum;
                    } else if (new_m == max_m[v] && new_sum < min_sum[v]) {
                        min_sum[v] = new_sum;
                    }
                }
            }
        }

        return max_m[n - 1] == Long.MIN_VALUE ? -1 : max_m[n - 1];
    }
}
